import{_ as t,o,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"工作原理","description":"","frontmatter":{},"headers":[],"relativePath":"zh/advanced/how-it-works.md","filePath":"zh/advanced/how-it-works.md"}'),l={name:"zh/advanced/how-it-works.md"};function i(s,e,n,c,h,d){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="工作原理" tabindex="-1"><i class="ph ph-lightbulb"></i> 工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-lightbulb&quot;&gt;&lt;/i&gt; 工作原理&quot;">​</a></h1><p>WebAP 高效的秘诀在于其模块化和数学方法。该插件不会尝试“猜测”延迟的原因或盲目降低屏幕分辨率。</p><p>整个系统作为一个由三个主要层组成的精细调整的管道运行：<strong>跟踪器 (Tracker)</strong>、<strong>索引器 (Indexer)</strong> 和 <strong>缩放器 (Scalers)</strong>。</p><h2 id="决策管道" tabindex="-1"><i class="ph ph-tree-view"></i> 决策管道 <a class="header-anchor" href="#决策管道" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-tree-view&quot;&gt;&lt;/i&gt; 决策管道&quot;">​</a></h2><p>插件架构严格分离了数据收集、决策和执行。</p><h3 id="_1-跟踪器-observer" tabindex="-1">1. 跟踪器 (Observer) <a class="header-anchor" href="#_1-跟踪器-observer" aria-label="Permalink to &quot;1. 跟踪器 (Observer)&quot;">​</a></h3><p>每帧，跟踪器 (Tracker) 收集有关帧时间和纯 CPU 时间的原始数据。它计算指数移动平均线 (Exponential Moving Average) 以平滑由垃圾回收器 (GC) 或资产加载引起的随机峰值。<br> 跟踪器不做出决定；它只回答两个问题：</p><ul><li><em>&quot;我们是否跟上了 Target Min FPS？&quot;</em></li><li><em>&quot;当前是哪个特定的子系统出现延迟（瓶颈）？&quot;</em></li></ul><h3 id="_2-索引器-brain" tabindex="-1">2. 索引器 (Brain) <a class="header-anchor" href="#_2-索引器-brain" aria-label="Permalink to &quot;2. 索引器 (Brain)&quot;">​</a></h3><p>索引器 (Indexer) 接收来自跟踪器的数据并决定如何继续。它是系统的仲裁者。<br> 如果 FPS 下降，索引器将：</p><ol><li>检查系统是否处于 <strong>冷却 (Cooldown)</strong> 状态。</li><li>评估 <strong>Anti Yo-Yo 惩罚系统</strong>（有关详细信息，请参阅 <a href="./anti-yoyo">Anti Yo-Yo 惩罚</a>）。</li><li>计算所有可用缩放器 (Scalers) 的成本。</li><li>向能以最小视觉损伤产生最大性能的缩放器发出命令。</li></ol><h3 id="_3-缩放器-executors" tabindex="-1">3. 缩放器 (Executors) <a class="header-anchor" href="#_3-缩放器-executors" aria-label="Permalink to &quot;3. 缩放器 (Executors)&quot;">​</a></h3><p>缩放器 (Scalers) 从索引器接收命令并执行繁重的工作。它们与 Unity API 交互并应用所需的设置（降低分辨率、剔除图层、禁用抗锯齿）。</p><h2 id="瓶颈-无需温度计即可寻找约束" tabindex="-1"><i class="ph ph-cpu"></i> 瓶颈：无需温度计即可寻找约束 <a class="header-anchor" href="#瓶颈-无需温度计即可寻找约束" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-cpu&quot;&gt;&lt;/i&gt; 瓶颈：无需温度计即可寻找约束&quot;">​</a></h2><p>WebAP 如何在无法访问设备传感器的情况下准确了解是什么无法处理负载？我们分析引擎本身的计时比例。</p><ul><li><strong>CPU 瓶颈：</strong> 跟踪器将纯处理器主线程时间除以总帧时间。如果该比率超过 <strong>85%</strong>，结论很明显。帧受逻辑或物理计算约束。降低屏幕分辨率或禁用阴影毫无用处。</li><li><strong>GPU 瓶颈：</strong> 如果整体 FPS 低于正常水平，但 CPU 份额不到 85%，则表明处理器处于空闲状态。显卡未能及时渲染帧（填充率瓶颈、复杂的着色器或过度绘制）。</li><li><strong>目标帧速率：</strong> 如果平均 VSync 等待时间大于零，则表示处理器和显卡完成渲染的速度快于显示器的刷新率。系统运行有性能余量 (Performance Headroom)，索引器可以平滑地提高图形质量。</li></ul><h2 id="zero-gc-性能第一" tabindex="-1"><i class="ph-fill ph-lightning"></i> Zero-GC：性能第一 <a class="header-anchor" href="#zero-gc-性能第一" aria-label="Permalink to &quot;&lt;i class=&quot;ph-fill ph-lightning&quot;&gt;&lt;/i&gt; Zero-GC：性能第一&quot;">​</a></h2><p>旨在将游戏从延迟中拯救出来的插件没有理由自身产生延迟。WebAP 核心的设计在热路径 (Hot Path) 上严格考虑了内存经济性 (Zero-GC)。</p><ul><li><strong>O(1) 环形缓冲区：</strong> 跟踪器不使用 <code>List&lt;float&gt;</code> 和 <code>Update</code> 中的繁重循环，而是使用固定大小的数组（环形缓冲区）。平均 FPS 计算在固定时间内执行。</li><li><strong><code>Update</code> 中零分配：</strong> 核心不包含 <code>new</code> 调用、装箱或 lambda。垃圾回收器 (GC) 根本不需要清理任何东西。</li><li><strong>委托缓存：</strong> 即使对于复杂的任务（拦截 <code>WebScaledPhysics2DRaycaster</code> 中的点击），我们放弃了缓慢的反射 (<code>MethodInfo.Invoke</code>)，转而支持快速编译的委托。</li></ul><div class="note custom-block github-alert"><p class="custom-block-title"><i class="ph-bold ph-note-pencil"></i> 隐形</p><p>归功于这些优化，整个 WebAP 管道的开销微乎其微。您的处理器甚至不会注意到它正在被监控。</p></div>',20)])])}const g=t(l,[["render",i]]);export{u as __pageData,g as default};
